+		_, _ = w.Write(buf)
+	}))
+	srv.TLS = &tls.Config{Certificates: []tls.Certificate{cert}}
+	srv.StartTLS()
+	defer srv.Close()
+
+	bootstrapIP, port, err := net.SplitHostPort(srv.Listener.Addr().String())
+	if err != nil {
