+	addrs, _, _, err := r.Lookup(ctx, "example.com")
+	if err != nil {
+		t.Fatalf("Lookup: unexpected error (bootstrap dial should have reached the hermetic listener without any DNS lookup of %q): %v", unresolvableHost, err)
