208		}
209		if u.Scheme != "https" {
210			return "", fmt.Errorf("must use https, got scheme %q in %q", u.Scheme, rawURL)
211		}
212		host := u.Hostname()
213		if host == "" {
214			return "", fmt.Errorf("missing host in %q", rawURL)
215		}
216		return host, nil
217	}
