252	//
253	// bootstrap_ip (validated fail-fast, see requireBootstrapForHost) IS wired
254	// into the constructed resolver's dial target: when set, the resolver dials
255	// bootstrap_ip directly instead of resolving the configured hostname through
256	// the system dialer — the BOOTSTRAP-IP invariant (Q33) exists precisely to
257	// avoid that plaintext lookup of the private resolver's own name.
258	func (d DNS) NewResolver() (dnsresolve.Resolver, error) {
259		switch d.Resolver {
260		case DNSResolverDoH:
261			if d.BootstrapIP != "" {
262				return dnsresolve.NewDoHResolverWithBootstrap(d.DoHURL, d.BootstrapIP)
263			}
264			return dnsresolve.NewDoHResolver(d.DoHURL)
265		case DNSResolverDoT:
266			host, err := dotServerHost(d.DoTServer)
267			if err != nil {
268				return nil, fmt.Errorf("dns.dot_server: %w", err)
269			}
270			if d.BootstrapIP != "" {
271				return dnsresolve.NewDoTResolverWithBootstrap(host, d.BootstrapIP)
272			}
273			return dnsresolve.NewDoTResolver(host)
274		default:
275			return dnsresolve.NewSystemResolver(), nil
276		}
277	}
